// Page trans
(function () {
  function init() {
    if (!window.gsap) return;

    const overlay = document.querySelector(".transition-overlay");
    if (!overlay) return;

    const blocks = Array.from(overlay.querySelectorAll(".block"));
    const CLOSED = 1.05;
    let isTransitioning = false;
    let hasRevealed = false;

    gsap.set(blocks, { force3D: true });

    function showOverlay() {
      overlay.style.visibility = "visible";
    }

    function hideOverlay() {
      overlay.style.visibility = "hidden";
    }

    function revealPage(force = false) {
      if (hasRevealed && !force) return;
      hasRevealed = true;

      showOverlay();
      gsap.killTweensOf(blocks);
      gsap.set(blocks, { scaleX: CLOSED, transformOrigin: "right" });

      gsap.to(blocks, {
        scaleX: 0,
        duration: 0.4,
        stagger: 0.02,
        ease: "power2.out",
        transformOrigin: "right",
        onComplete: () => {
          hideOverlay();
          isTransitioning = false;
        }
      });
    }

    function coverPage(url) {
      if (isTransitioning) return;
      isTransitioning = true;

      showOverlay();
      gsap.killTweensOf(blocks);
      gsap.set(blocks, { scaleX: 0, transformOrigin: "left" });

      gsap.to(blocks, {
        scaleX: CLOSED,
        duration: 0.4,
        stagger: 0.02,
        ease: "power2.out",
        transformOrigin: "left",
        onComplete: () => {
          window.location.href = url;
        }
      });
    }

    function isInternalNav(link) {
      const href = link.getAttribute("href");
      if (!href) return false;
      if (href.startsWith("#")) return false;
      if (/^(mailto:|tel:)/i.test(href)) return false;
      if (link.hasAttribute("target")) return false;
      if (link.hasAttribute("download")) return false;

      try {
        const u = new URL(link.href, window.location.origin);
        return u.origin === window.location.origin;
      } catch {
        return false;
      }
    }

    document.querySelectorAll("a[href]").forEach((link) => {
      if (!isInternalNav(link)) return;

      link.addEventListener("click", (e) => {
        e.preventDefault();
        coverPage(link.href);
      });
    });

    document.addEventListener("DOMContentLoaded", () => revealPage(), { once: true });

    window.addEventListener("pageshow", (e) => {
      if (e.persisted) {
        revealPage(true);
      }
    });

    if (document.readyState === "interactive" || document.readyState === "complete") {
      requestAnimationFrame(() => revealPage());
    }
  }

  (window.Webflow ||= []).push(() => {
    let tries = 0;
    const t = setInterval(() => {
      tries++;

      if (window.gsap) {
        clearInterval(t);
        init();
      } else if (tries >= 80) {
        clearInterval(t);
        const overlay = document.querySelector(".transition-overlay");
        if (overlay) overlay.style.visibility = "hidden";
      }
    }, 50);
  });
})();

// Products swiper
function initSwiperProducts() {
  const swiperEl = document.querySelector(".swiper-products");
  if (!swiperEl || typeof Swiper === "undefined") return;

  swiperEl.setAttribute("tabindex", "0");

  const swiper = new Swiper(swiperEl, {
    loop: false,
    speed: 500,
    slidesPerView: "auto",
    spaceBetween: 24,
    centeredSlides: true,
    centeredSlidesBounds: true,
    slideToClickedSlide: true,
    allowTouchMove: true,
    slidesOffsetAfter: 64,
    keyboard: {
      enabled: true,
      onlyInViewport: true,
      pageUpDown: true
    },
    a11y: {
      enabled: true
    },
    pagination: {
      el: ".swiper-pagination",
      clickable: true
    },
    navigation: {
      nextEl: ".product_next",
      prevEl: ".product_prev"
    },
    breakpoints: {
      768: {
        slidesPerView: "auto",
        spaceBetween: 24,
        centeredSlides: false,
        centeredSlidesBounds: false
      },
      1280: {
        slidesPerView: "auto",
        spaceBetween: 32,
        centeredSlides: false,
        slidesOffsetAfter: 228,
        centeredSlidesBounds: false
      }
    }
  });

  swiperEl.querySelectorAll(".swiper-slide.is--product").forEach((slide, i) => {
    slide.setAttribute("tabindex", "0");

    slide.addEventListener("keydown", (e) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        swiper.slideTo(i);
      }
    });
  });
}

function initSwiperTeam() {
  const swiperEl = document.querySelector(".swiper-team");
  if (!swiperEl || typeof Swiper === "undefined") return;

  swiperEl.setAttribute("tabindex", "0");

  const swiper = new Swiper(swiperEl, {
    loop: false,
    speed: 700,
    slidesPerView: "auto",
    slidesPerGroup: 1,
    spaceBetween: 16,
    centeredSlides: false,
    centeredSlidesBounds: false,
    slideToClickedSlide: true,
    allowTouchMove: true,
    watchOverflow: true,
    observer: true,
    observeParents: true,
    a11y: {
      enabled: true
    },
    navigation: {
      nextEl: ".team-next",
      prevEl: ".team-prev"
    },
    breakpoints: {
      768: {
        slidesPerView: "auto",
        spaceBetween: 16
      },
      1280: {
        slidesPerView: "auto",
        spaceBetween: 16
      },
      1440: {
        slidesPerView: "auto",
        spaceBetween: 16
      },
      1920: {
        slidesPerView: "auto",
        spaceBetween: 16
      }
    }
  });

  let isActive = false;

  swiperEl.addEventListener("focusin", () => {
    isActive = true;
  });

  swiperEl.addEventListener("focusout", (e) => {
    if (!swiperEl.contains(e.relatedTarget)) {
      isActive = false;
    }
  });

  swiperEl.addEventListener("mouseenter", () => {
    isActive = true;
  });

  swiperEl.addEventListener("mouseleave", () => {
    isActive = false;
  });

  swiperEl.addEventListener("click", () => {
    swiperEl.focus();
    isActive = true;
  });

  swiperEl.addEventListener("keydown", (e) => {
    if (!isActive) return;

    if (e.key === "ArrowRight") {
      e.preventDefault();
      e.stopPropagation();
      swiper.slideNext();
    }

    if (e.key === "ArrowLeft") {
      e.preventDefault();
      e.stopPropagation();
      swiper.slidePrev();
    }
  });

  swiperEl.querySelectorAll(".swiper-slide").forEach((slide, i) => {
    slide.setAttribute("tabindex", "0");

    slide.addEventListener("keydown", (e) => {
      if (!isActive) return;

      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        e.stopPropagation();
        swiper.slideTo(i);
      }

      if (e.key === "ArrowRight") {
        e.preventDefault();
        e.stopPropagation();
        swiper.slideNext();
      }

      if (e.key === "ArrowLeft") {
        e.preventDefault();
        e.stopPropagation();
        swiper.slidePrev();
      }
    });
  });
}

function initTeamCardZoom() {
  if (typeof gsap === "undefined") return;

  const teamCards = document.querySelectorAll(".slide_inner.is--team");

  teamCards.forEach((card) => {
    const img = card.querySelector(".people_img");

    card.addEventListener("mouseenter", () => {
      if (img) {
        gsap.to(img, {
          scale: 1.05,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });

    card.addEventListener("mouseleave", () => {
      if (img) {
        gsap.to(img, {
          scale: 1,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });
  });
}

function initAll() {
  initSwiperProducts();
  initSwiperTeam();
  initTeamCardZoom();
}

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", initAll);
} else {
  initAll();
}

// Lenis
const lenis = new Lenis({
  duration: 1,
  easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
  smooth: true
});

function raf(time) {
  lenis.raf(time);
  requestAnimationFrame(raf);
}
requestAnimationFrame(raf);

window.lenis = lenis;

/* Highlight text */
gsap.registerPlugin(ScrollTrigger, SplitText);

function initHighlightText() {
  const splitHeadingTargets = document.querySelectorAll("[data-highlight-text]");

  splitHeadingTargets.forEach((heading) => {
    const scrollStart = heading.getAttribute("data-highlight-scroll-start") || "top 90%";
    const scrollEnd = heading.getAttribute("data-highlight-scroll-end") || "center 40%";
    const fadedValue = heading.getAttribute("data-highlight-fade") || 0.2;
    const staggerValue = heading.getAttribute("data-highlight-stagger") || 0.1;

    new SplitText(heading, {
      type: "words, chars",
      autoSplit: true,
      onSplit(self) {
        const ctx = gsap.context(() => {
          const tl = gsap.timeline({
            scrollTrigger: {
              scrub: true,
              trigger: heading,
              start: scrollStart,
              end: scrollEnd
            }
          });

          tl.from(self.chars, {
            autoAlpha: fadedValue,
            stagger: staggerValue,
            ease: "linear"
          });
        });

        return ctx;
      }
    });
  });
}

document.addEventListener("DOMContentLoaded", () => {
  initHighlightText();
});

/* Button Script */
function initButtonCharacterStagger() {
  if (window.innerWidth <= 767) return;

  const offsetIncrement = 0.01;
  const buttons = document.querySelectorAll("[data-button-animate-chars]");

  buttons.forEach((button) => {
    const text = button.textContent;
    button.innerHTML = "";

    [...text].forEach((char, index) => {
      const span = document.createElement("span");
      span.textContent = char;
      span.style.transitionDelay = `${index * offsetIncrement}s`;

      if (char === " ") {
        span.style.whiteSpace = "pre";
      }

      button.appendChild(span);
    });
  });
}

document.addEventListener("DOMContentLoaded", () => {
  initButtonCharacterStagger();
});

// Alternative H1 animation
window.animateSplitHeading = function (selector, options = {}) {
  const el = typeof selector === "string"
    ? document.querySelector(selector)
    : selector;

  if (!el) return;

  const {
    yFrom = 20,
    delay = 0.35,
    duration = 0.8,
    stagger = 0.018,
    ease = "power3.out"
  } = options;

  const aria = el.textContent.trim();
  el.setAttribute("aria-label", aria);

  const nodes = Array.from(el.childNodes);
  let html = "";

  nodes.forEach((node) => {
    if (node.nodeType === 1 && node.tagName === "BR") {
      html += "<br>";
      return;
    }

    if (node.nodeType === 3) {
      const words = node.textContent.split(/\s+/).filter(Boolean);

      words.forEach((word) => {
        html += `<span class="hero-word">`;

        for (const ch of word) {
          html += `<span class="hero-char">${ch}</span>`;
        }

        html += `</span>`;
        html += `<span class="hero-space">&nbsp;</span>`;
      });
    }
  });

  el.innerHTML = html.trim();

  const chars = el.querySelectorAll(".hero-char");

  gsap.set(chars, {
    opacity: 0,
    y: yFrom
  });

  gsap.to(chars, {
    opacity: 1,
    y: 0,
    delay,
    duration,
    ease,
    stagger
  });
};

(window.Webflow ||= []).push(() => {
  if (window.animateSplitHeading) {
    window.animateSplitHeading(".heading-h1_alt", {
      breakBeforeLastWords: 0,
      delay: 0.3
    });
  }
});

// Bunny Player
function initBunnyLightboxPlayer() {
  var player = document.querySelector("[data-bunny-lightbox-init]");
  if (!player) return;

  var wrapper = player.closest("[data-bunny-lightbox-status]");
  if (!wrapper) return;

  var video = player.querySelector("video");
  if (!video) return;

  try { video.pause(); } catch (_) {}
  try { video.removeAttribute("src"); video.load(); } catch (_) {}

  function setAttr(el, name, val) {
    var str = (typeof val === "boolean") ? (val ? "true" : "false") : String(val);
    if (el.getAttribute(name) !== str) el.setAttribute(name, str);
  }

  function setStatus(s) { setAttr(player, "data-player-status", s); }
  function setMutedState(v) { video.muted = !!v; setAttr(player, "data-player-muted", video.muted); }
  function setFsAttr(v) { setAttr(player, "data-player-fullscreen", !!v); }
  function setActivated(v) { setAttr(player, "data-player-activated", !!v); }

  if (!player.hasAttribute("data-player-activated")) setActivated(false);

  var timeline = player.querySelector("[data-player-timeline]");
  var progressBar = player.querySelector("[data-player-progress]");
  var bufferedBar = player.querySelector("[data-player-buffered]");
  var handle = player.querySelector("[data-player-timeline-handle]");
  var timeDurationEls = player.querySelectorAll("[data-player-time-duration]");
  var timeProgressEls = player.querySelectorAll("[data-player-time-progress]");
  var playerPlaceholderImg = player.querySelector("[data-bunny-lightbox-placeholder]");

  var updateSize = player.getAttribute("data-player-update-size");
  var autoplay = player.getAttribute("data-player-autoplay") === "true";
  var initialMuted = player.getAttribute("data-player-muted") === "true";

  var pendingPlay = false;

  video.loop = false;
  setMutedState(initialMuted);

  video.setAttribute("playsinline", "");
  video.setAttribute("webkit-playsinline", "");
  video.playsInline = true;
  if (typeof video.disableRemotePlayback !== "undefined") video.disableRemotePlayback = true;
  if (autoplay) video.autoplay = false;

  var isSafariNative = !!video.canPlayType("application/vnd.apple.mpegurl");
  var canUseHlsJs = !!(window.Hls && Hls.isSupported()) && !isSafariNative;

  var isAttached = false;
  var currentSrc = "";
  var lastPauseBy = "";
  var rafId;
  var autoStartOnReady = false;

  function setupLightboxClamp(player, wrapper, video, updateSize) {
    var calcBox = wrapper.querySelector("[data-bunny-lightbox-calc-height]");
    if (!calcBox) return;

    function getRatio() {
      if (updateSize === "cover") return null;

      if (updateSize === "true") {
        if (video.videoWidth && video.videoHeight) return video.videoWidth / video.videoHeight;

        var before = player.querySelector("[data-player-before]");
        if (before && before.style && before.style.paddingTop) {
          var pct = parseFloat(before.style.paddingTop);
          if (pct > 0) return 100 / pct;
        }

        var r = player.getBoundingClientRect();
        if (r.height > 0) return r.width / r.height;
        return 16 / 9;
      }

      var beforeFalse = player.querySelector("[data-player-before]");
      if (beforeFalse && beforeFalse.style && beforeFalse.style.paddingTop) {
        var pad = parseFloat(beforeFalse.style.paddingTop);
        if (pad > 0) return 100 / pad;
      }

      var rb = player.getBoundingClientRect();
      if (rb.height > 0) return rb.width / rb.height;
      return 16 / 9;
    }

    function applyClamp() {
      if (updateSize === "cover") {
        calcBox.style.maxWidth = "";
        calcBox.style.maxHeight = "";
        return;
      }

      var parent = wrapper;
      var cs = getComputedStyle(parent);
      var pt = parseFloat(cs.paddingTop) || 0;
      var pb = parseFloat(cs.paddingBottom) || 0;
      var pl = parseFloat(cs.paddingLeft) || 0;
      var pr = parseFloat(cs.paddingRight) || 0;

      var cw = parent.clientWidth - pl - pr;
      var ch = parent.clientHeight - pt - pb;
      if (cw <= 0 || ch <= 0) return;

      var ratio = getRatio();
      if (!ratio) {
        calcBox.style.maxWidth = "";
        calcBox.style.maxHeight = "";
        return;
      }

      var hIfFullWidth = cw / ratio;

      if (hIfFullWidth <= ch) {
        calcBox.style.maxWidth = "100%";
        calcBox.style.maxHeight = (hIfFullWidth / ch * 100) + "%";
      } else {
        calcBox.style.maxHeight = "100%";
        calcBox.style.maxWidth = ((ch * ratio) / cw * 100) + "%";
      }
    }

    var rafPending = false;

    function debouncedApply() {
      if (rafPending) return;
      if (wrapper.getAttribute("data-bunny-lightbox-status") !== "active") return;

      rafPending = true;
      requestAnimationFrame(function () {
        rafPending = false;
        applyClamp();
      });
    }

    var ro = new ResizeObserver(debouncedApply);
    ro.observe(wrapper);

    window.addEventListener("resize", debouncedApply);
    window.addEventListener("orientationchange", debouncedApply);

    if (updateSize === "true") {
      video.addEventListener("loadedmetadata", debouncedApply);
      video.addEventListener("loadeddata", debouncedApply);
      video.addEventListener("playing", debouncedApply);
    }

    player._applyClamp = debouncedApply;
    debouncedApply();
  }

  setupLightboxClamp(player, wrapper, video, updateSize);

  function withAttach(src, onReady) {
    if (isSafariNative) {
      video.preload = "auto";
      video.src = src;
      video.addEventListener("loadedmetadata", onReady, { once: true });
      return;
    }

    if (canUseHlsJs) {
      var hls = new Hls({ maxBufferLength: 10 });
      player._hls = hls;
      hls.attachMedia(video);
      hls.on(Hls.Events.MEDIA_ATTACHED, function () { hls.loadSource(src); });
      hls.on(Hls.Events.MANIFEST_PARSED, function () { onReady(); });
      hls.on(Hls.Events.LEVEL_LOADED, function (e, data) {
        if (data && data.details && isFinite(data.details.totalduration) && timeDurationEls.length) {
          setText(timeDurationEls, formatTime(data.details.totalduration));
        }
      });
      return;
    }

    video.preload = "auto";
    video.src = src;
    video.addEventListener("loadedmetadata", onReady, { once: true });
  }

  function attachMediaFor(src) {
    if (currentSrc === src && isAttached) return;

    if (player._hls) {
      try { player._hls.destroy(); } catch (_) {}
      player._hls = null;
    }

    if (timeDurationEls.length) setText(timeDurationEls, "00:00");

    currentSrc = src;
    isAttached = true;

    withAttach(src, function onReady() {
      readyIfIdle(player, pendingPlay);
      updateBeforeRatioIOSSafe();

      if (typeof player._applyClamp === "function") player._applyClamp();
      if (timeDurationEls.length && video.duration) setText(timeDurationEls, formatTime(video.duration));

      if (autoStartOnReady && wrapper.getAttribute("data-bunny-lightbox-status") === "active") {
        setStatus("loading");
        safePlay(video);
        autoStartOnReady = false;
      }
    });
  }

  function ensureOpenUI(isActive) {
    var state = isActive ? "active" : "not-active";
    if (wrapper.getAttribute("data-bunny-lightbox-status") !== state) {
      wrapper.setAttribute("data-bunny-lightbox-status", state);
    }
    if (isActive && typeof player._applyClamp === "function") player._applyClamp();
  }

  function isSameSrc(next) {
    return currentSrc && currentSrc === next;
  }

  function planOnOpen(next) {
    var same = isSameSrc(next);

    if (!same) {
      try { if (!video.paused && !video.ended) video.pause(); } catch (_) {}
      if (player._hls) {
        try { player._hls.destroy(); } catch (_) {}
        player._hls = null;
      }

      isAttached = false;
      currentSrc = "";

      if (timeDurationEls.length) setText(timeDurationEls, "00:00");

      setActivated(false);
      setStatus("idle");

      attachMediaFor(next);
      autoStartOnReady = !!autoplay;
      pendingPlay = !!autoplay;
      return;
    }

    autoStartOnReady = !!autoplay;

    if (autoplay) {
      setStatus("loading");
      safePlay(video);
    } else {
      try { if (!video.paused && !video.ended) video.pause(); } catch (_) {}
      setActivated(false);
      setStatus("paused");
    }
  }

  function openLightbox(src, placeholderUrl) {
    if (!src) return;

    function activate() {
      ensureOpenUI(true);
      planOnOpen(src);
    }

    if (playerPlaceholderImg && placeholderUrl) {
      var needsSwap = playerPlaceholderImg.getAttribute("src") !== placeholderUrl;

      if (needsSwap || !playerPlaceholderImg.complete || !playerPlaceholderImg.naturalWidth) {
        playerPlaceholderImg.onload = function () {
          playerPlaceholderImg.onload = null;
          activate();
        };

        playerPlaceholderImg.onerror = function () {
          playerPlaceholderImg.onerror = null;
          activate();
        };

        if (needsSwap) {
          playerPlaceholderImg.setAttribute("src", placeholderUrl);
        } else {
          playerPlaceholderImg.dispatchEvent(new Event("load"));
        }
      } else {
        activate();
      }
    } else {
      activate();
    }
  }

  function togglePlay() {
    if (video.paused || video.ended) {
      pendingPlay = true;
      lastPauseBy = "";
      setStatus("loading");
      safePlay(video);
    } else {
      lastPauseBy = "manual";
      video.pause();
    }
  }

  function toggleMute() {
    setMutedState(!video.muted);
  }

  player.addEventListener("click", function (e) {
    var btn = e.target.closest("[data-player-control]");
    if (!btn || !player.contains(btn)) return;

    var type = btn.getAttribute("data-player-control");
    if (type === "play" || type === "pause" || type === "playpause") togglePlay();
    else if (type === "mute") toggleMute();
    else if (type === "fullscreen") toggleFullscreen();
  });

  function isFsActive() {
    return !!(document.fullscreenElement || document.webkitFullscreenElement);
  }

  function enterFullscreen() {
    if (player.requestFullscreen) return player.requestFullscreen();
    if (video.requestFullscreen) return video.requestFullscreen();
    if (video.webkitSupportsFullscreen && typeof video.webkitEnterFullscreen === "function") {
      return video.webkitEnterFullscreen();
    }
  }

  function exitFullscreen() {
    if (document.exitFullscreen) return document.exitFullscreen();
    if (document.webkitExitFullscreen) return document.webkitExitFullscreen();
    if (video.webkitDisplayingFullscreen && typeof video.webkitExitFullscreen === "function") {
      return video.webkitExitFullscreen();
    }
  }

  function toggleFullscreen() {
    if (isFsActive() || video.webkitDisplayingFullscreen) exitFullscreen();
    else enterFullscreen();
  }

  document.addEventListener("fullscreenchange", function () { setFsAttr(isFsActive()); });
  document.addEventListener("webkitfullscreenchange", function () { setFsAttr(isFsActive()); });
  video.addEventListener("webkitbeginfullscreen", function () { setFsAttr(true); });
  video.addEventListener("webkitendfullscreen", function () { setFsAttr(false); });

  function updateTimeTexts() {
    if (timeDurationEls.length) setText(timeDurationEls, formatTime(video.duration));
    if (timeProgressEls.length) setText(timeProgressEls, formatTime(video.currentTime));
  }

  video.addEventListener("timeupdate", updateTimeTexts);
  video.addEventListener("loadedmetadata", function () { updateTimeTexts(); updateBeforeRatioIOSSafe(); });
  video.addEventListener("loadeddata", function () { updateBeforeRatioIOSSafe(); });
  video.addEventListener("playing", function () { updateBeforeRatioIOSSafe(); });
  video.addEventListener("durationchange", updateTimeTexts);

  function updateProgressVisuals() {
    if (!video.duration) return;

    var playedPct = (video.currentTime / video.duration) * 100;
    if (progressBar) progressBar.style.transform = "translateX(" + (-100 + playedPct) + "%)";
    if (handle) handle.style.left = pctClamp(playedPct) + "%";
  }

  function pctClamp(p) {
    return p < 0 ? 0 : p > 100 ? 100 : p;
  }

  function loop() {
    updateProgressVisuals();
    if (!video.paused && !video.ended) rafId = requestAnimationFrame(loop);
  }

  function updateBufferedBar() {
    if (!bufferedBar || !video.duration || !video.buffered.length) return;

    var end = video.buffered.end(video.buffered.length - 1);
    var buffPct = (end / video.duration) * 100;
    bufferedBar.style.transform = "translateX(" + (-100 + buffPct) + "%)";
  }

  video.addEventListener("progress", updateBufferedBar);
  video.addEventListener("loadedmetadata", updateBufferedBar);
  video.addEventListener("durationchange", updateBufferedBar);

  video.addEventListener("play", function () {
    setActivated(true);
    cancelAnimationFrame(rafId);
    loop();
    setStatus("playing");
  });

  video.addEventListener("playing", function () {
    pendingPlay = false;
    setStatus("playing");
  });

  video.addEventListener("pause", function () {
    pendingPlay = false;
    cancelAnimationFrame(rafId);
    updateProgressVisuals();
    setStatus("paused");
  });

  video.addEventListener("waiting", function () {
    setStatus("loading");
  });

  video.addEventListener("canplay", function () {
    readyIfIdle(player, pendingPlay);
  });

  video.addEventListener("ended", function () {
    pendingPlay = false;
    cancelAnimationFrame(rafId);
    updateProgressVisuals();
    setActivated(false);
    video.currentTime = 0;

    if (document.fullscreenElement || document.webkitFullscreenElement || video.webkitDisplayingFullscreen) {
      if (document.exitFullscreen) document.exitFullscreen();
      else if (document.webkitExitFullscreen) document.webkitExitFullscreen();
      else if (video.webkitExitFullscreen) video.webkitExitFullscreen();
    }

    closeLightbox();
  });

  if (timeline) {
    var dragging = false;
    var wasPlaying = false;
    var targetTime = 0;
    var lastSeekTs = 0;
    var seekThrottle = 180;
    var rect = null;

    window.addEventListener("resize", function () {
      if (!dragging) rect = null;
    });

    function getFractionFromX(x) {
      if (!rect) rect = timeline.getBoundingClientRect();
      var f = (x - rect.left) / rect.width;
      if (f < 0) f = 0;
      if (f > 1) f = 1;
      return f;
    }

    function previewAtFraction(f) {
      if (!video.duration) return;

      var pct = f * 100;
      if (progressBar) progressBar.style.transform = "translateX(" + (-100 + pct) + "%)";
      if (handle) handle.style.left = pct + "%";
      if (timeProgressEls.length) setText(timeProgressEls, formatTime(f * video.duration));
    }

    function maybeSeek(now) {
      if (!video.duration) return;
      if ((now - lastSeekTs) < seekThrottle) return;

      lastSeekTs = now;
      video.currentTime = targetTime;
    }

    function onPointerDown(e) {
      if (!video.duration) return;

      dragging = true;
      wasPlaying = !video.paused && !video.ended;
      if (wasPlaying) video.pause();

      player.setAttribute("data-timeline-drag", "true");
      rect = timeline.getBoundingClientRect();

      var f = getFractionFromX(e.clientX);
      targetTime = f * video.duration;
      previewAtFraction(f);
      maybeSeek(performance.now());

      if (timeline.setPointerCapture) timeline.setPointerCapture(e.pointerId);

      window.addEventListener("pointermove", onPointerMove, { passive: false });
      window.addEventListener("pointerup", onPointerUp, { passive: true });
      e.preventDefault();
    }

    function onPointerMove(e) {
      if (!dragging) return;

      var f = getFractionFromX(e.clientX);
      targetTime = f * video.duration;
      previewAtFraction(f);
      maybeSeek(performance.now());
      e.preventDefault();
    }

    function onPointerUp() {
      if (!dragging) return;

      dragging = false;
      player.setAttribute("data-timeline-drag", "false");
      rect = null;
      video.currentTime = targetTime;

      if (wasPlaying) safePlay(video);
      else {
        updateProgressVisuals();
        updateTimeTexts();
      }

      window.removeEventListener("pointermove", onPointerMove);
      window.removeEventListener("pointerup", onPointerUp);
    }

    timeline.addEventListener("pointerdown", onPointerDown, { passive: false });
    if (handle) handle.addEventListener("pointerdown", onPointerDown, { passive: false });
  }

  var hoverTimer;
  var hoverHideDelay = 3000;

  function setHover(state) {
    if (player.getAttribute("data-player-hover") !== state) {
      player.setAttribute("data-player-hover", state);
    }
  }

  function scheduleHide() {
    clearTimeout(hoverTimer);
    hoverTimer = setTimeout(function () {
      setHover("idle");
    }, hoverHideDelay);
  }

  function wakeControls() {
    setHover("active");
    scheduleHide();
  }

  player.addEventListener("pointerdown", wakeControls);
  document.addEventListener("fullscreenchange", wakeControls);
  document.addEventListener("webkitfullscreenchange", wakeControls);

  var trackingMove = false;

  function onPointerMoveGlobal(e) {
    var r = player.getBoundingClientRect();
    if (e.clientX >= r.left && e.clientX <= r.right && e.clientY >= r.top && e.clientY <= r.bottom) {
      wakeControls();
    }
  }

  player.addEventListener("pointerenter", function () {
    wakeControls();
    if (!trackingMove) {
      trackingMove = true;
      window.addEventListener("pointermove", onPointerMoveGlobal, { passive: true });
    }
  });

  player.addEventListener("pointerleave", function () {
    setHover("idle");
    clearTimeout(hoverTimer);

    if (trackingMove) {
      trackingMove = false;
      window.removeEventListener("pointermove", onPointerMoveGlobal);
    }
  });

  function closeLightbox() {
    ensureOpenUI(false);

    var hasPlayed = false;
    try {
      if (video.played && video.played.length) {
        for (var i = 0; i < video.played.length; i++) {
          if (video.played.end(i) > 0) {
            hasPlayed = true;
            break;
          }
        }
      } else {
        hasPlayed = video.currentTime > 0;
      }
    } catch (_) {}

    try { if (!video.paused && !video.ended) video.pause(); } catch (_) {}

    setActivated(false);
    setStatus(hasPlayed ? "paused" : "idle");
  }

  document.addEventListener("click", function (e) {
    var openBtn = e.target.closest('[data-bunny-lightbox-control="open"]');
    if (openBtn) {
      var src = openBtn.getAttribute("data-bunny-lightbox-src") || "";
      if (!src) return;

      var imgEl = openBtn.querySelector("[data-bunny-lightbox-placeholder]");
      var placeholderUrl = imgEl ? imgEl.getAttribute("src") : "";
      openLightbox(src, placeholderUrl);
      return;
    }

    var closeBtn = e.target.closest('[data-bunny-lightbox-control="close"]');
    if (closeBtn) {
      var closeInWrapper = closeBtn.closest("[data-bunny-lightbox-status]");
      if (closeInWrapper === wrapper) closeLightbox();
      return;
    }
  });

  document.addEventListener("keydown", function (e) {
    if (e.key === "Escape") closeLightbox();
  });

  function pad2(n) {
    return (n < 10 ? "0" : "") + n;
  }

  function formatTime(sec) {
    if (!isFinite(sec) || sec < 0) return "00:00";

    var s = Math.floor(sec);
    var h = Math.floor(s / 3600);
    var m = Math.floor((s % 3600) / 60);
    var r = s % 60;

    return h > 0 ? (h + ":" + pad2(m) + ":" + pad2(r)) : (pad2(m) + ":" + pad2(r));
  }

  function setText(nodes, text) {
    nodes.forEach(function (n) {
      n.textContent = text;
    });
  }

  function bestLevel(levels) {
    if (!levels || !levels.length) return null;
    return levels.reduce(function (a, b) {
      return ((b.width || 0) > (a.width || 0)) ? b : a;
    }, levels[0]);
  }

  function safePlay(video) {
    var p = video.play();
    if (p && typeof p.then === "function") p.catch(function () {});
  }

  function readyIfIdle(player, pendingPlay) {
    if (
      !pendingPlay &&
      player.getAttribute("data-player-activated") !== "true" &&
      player.getAttribute("data-player-status") === "idle"
    ) {
      player.setAttribute("data-player-status", "ready");
    }
  }

  function setBeforeRatio(player, updateSize, w, h) {
    if (updateSize !== "true" || !w || !h) return;
    var before = player.querySelector("[data-player-before]");
    if (!before) return;
    before.style.paddingTop = (h / w * 100) + "%";
  }

  function maybeSetRatioFromVideo(player, updateSize, video) {
    if (updateSize !== "true") return;
    var before = player.querySelector("[data-player-before]");
    if (!before) return;

    var hasPad = before.style.paddingTop && before.style.paddingTop !== "0%";
    if (!hasPad && video.videoWidth && video.videoHeight) {
      setBeforeRatio(player, updateSize, video.videoWidth, video.videoHeight);
    }
  }

  function updateBeforeRatioIOSSafe() {
    if (updateSize !== "true") return;

    var before = player.querySelector("[data-player-before]");
    if (!before) return;

    function apply(w, h) {
      if (!w || !h) return;
      before.style.paddingTop = (h / w * 100) + "%";
      if (typeof player._applyClamp === "function") player._applyClamp();
    }

    if (video.videoWidth && video.videoHeight) {
      apply(video.videoWidth, video.videoHeight);
      return;
    }

    if (player._hls && player._hls.levels && player._hls.levels.length) {
      var lvls = player._hls.levels;
      var best = lvls.reduce(function (a, b) {
        return ((b.width || 0) > (a.width || 0)) ? b : a;
      }, lvls[0]);

      if (best && best.width && best.height) {
        apply(best.width, best.height);
        return;
      }
    }

    requestAnimationFrame(function () {
      if (video.videoWidth && video.videoHeight) {
        apply(video.videoWidth, video.videoHeight);
        return;
      }

      var master = (typeof currentSrc === "string" && currentSrc) ? currentSrc : "";
      if (!master || master.indexOf("blob:") === 0) {
        var attrSrc = player.getAttribute("data-bunny-lightbox-src") || player.getAttribute("data-player-src") || "";
        if (attrSrc && attrSrc.indexOf("blob:") !== 0) master = attrSrc;
      }

      if (!master || !/^https?:/i.test(master)) return;

      fetch(master, { credentials: "omit", cache: "no-store" })
        .then(function (r) {
          if (!r.ok) throw new Error();
          return r.text();
        })
        .then(function (txt) {
          var lines = txt.split(/\r?\n/);
          var bestW = 0;
          var bestH = 0;
          var last = null;

          for (var i = 0; i < lines.length; i++) {
            var line = lines[i];

            if (line.indexOf("#EXT-X-STREAM-INF:") === 0) {
              last = line;
            } else if (last && line && line[0] !== "#") {
              var m = /RESOLUTION=(\d+)x(\d+)/.exec(last);
              if (m) {
                var W = parseInt(m[1], 10);
                var H = parseInt(m[2], 10);
                if (W > bestW) {
                  bestW = W;
                  bestH = H;
                }
              }
              last = null;
            }
          }

          if (bestW && bestH) apply(bestW, bestH);
        })
        .catch(function () {});
    });
  }
}

document.addEventListener("DOMContentLoaded", function () {
  initBunnyLightboxPlayer();
});

// Navigation
document.addEventListener("DOMContentLoaded", function () {
  const mq = window.matchMedia("(max-width: 991px)");

  const button = document.querySelector(".hamburger_button");
  const navItems = document.querySelector(".nav_items");
  const logo = document.querySelector(".logo_wrap");
  const lines = document.querySelectorAll(".hamburger_line");
  const navLinks = document.querySelectorAll(".nav_link");

  if (!button || !navItems) return;

  let isOpen = false;

  function getLenisInstance() {
    return window.lenis || (typeof lenis !== "undefined" ? lenis : null);
  }

  function setupForBreakpoint(matches) {
    if (!matches) {
      gsap.set(navItems, { clearProps: "all" });
      gsap.set(navLinks, { clearProps: "all" });
      if (logo) gsap.set(logo, { clearProps: "color" });
      if (button) gsap.set(button, { clearProps: "backgroundColor" });
      if (lines.length) gsap.set(lines, { clearProps: "backgroundColor" });

      animateHamburgerClose();

      const lenisInstance = getLenisInstance();
      if (lenisInstance && lenisInstance.start) lenisInstance.start();
      document.body.style.overflow = "";

      isOpen = false;
      return;
    }

    gsap.set(navItems, { yPercent: -101, display: "none" });
    gsap.set(navLinks, { opacity: 0, y: 10 });
    animateHamburgerClose();
  }

  setupForBreakpoint(mq.matches);
  mq.addEventListener("change", (e) => setupForBreakpoint(e.matches));

  function animateHamburgerOpen() {
    const top = document.querySelector(".hamburger_line.is--top");
    const bottom = document.querySelector(".hamburger_line:not(.is--top)");

    gsap.to(top, {
      y: 6,
      rotate: 45,
      duration: 0.35,
      ease: "power3.inOut"
    });

    gsap.to(bottom, {
      y: -6,
      rotate: -45,
      duration: 0.35,
      ease: "power3.inOut"
    });
  }

  function animateHamburgerClose() {
    const top = document.querySelector(".hamburger_line.is--top");
    const bottom = document.querySelector(".hamburger_line:not(.is--top)");

    gsap.to(top, {
      y: 0,
      rotate: 0,
      duration: 0.35,
      ease: "power3.inOut"
    });

    gsap.to(bottom, {
      y: 0,
      rotate: 0,
      duration: 0.35,
      ease: "power3.inOut"
    });
  }

  function openMenu() {
    if (!mq.matches) return;

    isOpen = true;

    gsap.set(navItems, { display: "flex" });

    gsap.to(navItems, {
      yPercent: 0,
      duration: 0.45,
      ease: "power3.inOut"
    });

    gsap.to(logo, {
      color: "#ffffff",
      duration: 0.3,
      ease: "power3.inOut"
    });

    gsap.to(button, {
      backgroundColor: "#a1f362",
      duration: 0.3,
      ease: "power3.inOut"
    });

    gsap.to(lines, {
      backgroundColor: "#042f24",
      duration: 0.3,
      ease: "power3.inOut"
    });

    gsap.to(navLinks, {
      opacity: 1,
      y: 0,
      duration: 0.45,
      ease: "power3.inOut",
      stagger: 0.07,
      delay: 0.15
    });

    animateHamburgerOpen();

    const lenisInstance = getLenisInstance();
    if (lenisInstance && lenisInstance.stop) {
      lenisInstance.stop();
    } else {
      document.body.style.overflow = "hidden";
    }
  }

  function closeMenu() {
    if (!mq.matches) return;

    isOpen = false;

    gsap.to(navLinks, {
      opacity: 0,
      y: 10,
      duration: 0.45,
      ease: "power3.inOut",
      stagger: -0.07
    });

    gsap.to(navItems, {
      yPercent: -101,
      delay: 0.35,
      duration: 0.55,
      ease: "power3.inOut",
      onComplete: () => {
        gsap.set(navItems, { display: "none" });
      }
    });

    gsap.to(logo, {
      color: "",
      duration: 0.3,
      ease: "power3.inOut"
    });

    gsap.to(button, {
      backgroundColor: "",
      duration: 0.3,
      ease: "power3.inOut"
    });

    gsap.to(lines, {
      backgroundColor: "",
      duration: 0.3,
      ease: "power3.inOut"
    });

    animateHamburgerClose();

    const lenisInstance = getLenisInstance();
    if (lenisInstance && lenisInstance.start) {
      lenisInstance.start();
    } else {
      document.body.style.overflow = "";
    }
  }

  button.addEventListener("click", function () {
    if (!mq.matches) return;
    isOpen ? closeMenu() : openMenu();
  });
});

// Swiper projects
function initSwiperProjects() {
  const swiperEl = document.querySelector(".swiper-projects");
  if (!swiperEl || typeof Swiper === "undefined") return;

  const wrapper = swiperEl.querySelector(".swiper-wrapper");
  const slides = wrapper.querySelectorAll(".swiper-slide");

  if (slides.length === 2) {
    slides.forEach(slide => {
      const clone = slide.cloneNode(true);
      wrapper.appendChild(clone);
    });
  }

  swiperEl.setAttribute("tabindex", "0");

  const swiper = new Swiper(swiperEl, {
    loop: true,
    speed: 700,
    slidesPerView: "auto",
    spaceBetween: 24,
    centeredSlides: true,
    slideToClickedSlide: true,
    allowTouchMove: true,
    navigation: {
      nextEl: ".button-next.project-next",
      prevEl: ".button-prev.project-prev"
    }
  });
  const targets = document.querySelectorAll("[data-project-target]");
  let isActive = false;

  function getActiveSlide() {
    const realIndex = swiper.realIndex;

    return swiperEl.querySelector(
      `.swiper-slide[data-swiper-slide-index="${realIndex}"]`
    );
  }

  function updateTargets() {
    const activeSlide = getActiveSlide();
    if (!activeSlide) return;

    const fields = activeSlide.querySelectorAll("[data-project-field]");

    fields.forEach((field) => {
      const key = field.getAttribute("data-project-field");

      const matchingTargets = document.querySelectorAll(
        `[data-project-target="${key}"]`
      );

      matchingTargets.forEach((target) => {
        target.innerHTML = field.innerHTML;
      });
    });
  }

  function fadeOut() {
    gsap.to(targets, {
      opacity: 0,
      duration: 0.15,
      ease: "power1.out"
    });
  }

  function fadeIn() {
    gsap.fromTo(
      targets,
      { opacity: 0 },
      {
        opacity: 1,
        duration: 0.25,
        ease: "power1.out"
      }
    );
  }

  swiper.on("slideChangeTransitionStart", fadeOut);

  swiper.on("slideChangeTransitionEnd", () => {
    updateTargets();
    fadeIn();
  });

  swiperEl.addEventListener("focusin", () => {
    isActive = true;
  });

  swiperEl.addEventListener("mouseenter", () => {
    isActive = true;
  });

  swiperEl.addEventListener("mouseleave", () => {
    isActive = false;
  });

  swiperEl.addEventListener("focusout", (e) => {
    if (!swiperEl.contains(e.relatedTarget)) {
      isActive = false;
    }
  });

  swiperEl.addEventListener("click", () => {
    swiperEl.focus();
    isActive = true;
  });

  swiperEl.addEventListener("keydown", function (e) {
    if (!isActive) return;

    if (e.key === "ArrowRight") {
      e.preventDefault();
      e.stopPropagation();
      swiper.slideNext();
    }

    if (e.key === "ArrowLeft") {
      e.preventDefault();
      e.stopPropagation();
      swiper.slidePrev();
    }
  });

  swiperEl.querySelectorAll(".swiper-slide").forEach((slide) => {
    slide.setAttribute("tabindex", "0");
  });

  updateTargets();
  fadeIn();
}

document.addEventListener("DOMContentLoaded", initSwiperProjects);


// Slide hover products
document.addEventListener("DOMContentLoaded", () => {
  const slides = document.querySelectorAll(".swiper-slide.is--product");

  slides.forEach((slide) => {
    const img = slide.querySelector(".product_img");

    slide.addEventListener("mouseenter", () => {
      slides.forEach((other) => {
        if (other !== slide) {
          gsap.to(other, { opacity: 0.3, duration: 0.3, ease: "power2.out" });
        }
      });

      if (img) {
        gsap.to(img, {
          scale: 1.05,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });

    slide.addEventListener("mouseleave", () => {
      gsap.to(slides, { opacity: 1, duration: 0.3, ease: "power2.out" });

      if (img) {
        gsap.to(img, {
          scale: 1,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });
  });
});

//Products animation
window.Webflow = window.Webflow || [];
  window.Webflow.push(function () {

    const mm = window.matchMedia("(min-width: 992px)");

    function init() {
      document.querySelectorAll(".product_item").forEach(function(item) {
        const img = item.querySelector(".product_list_img");
        const paragraph = item.querySelector(".product_paragraph");
        const wrapper = item.querySelector(".product_paragraph_wrapper");
        const left = item.querySelector(".product_item_left");
        const inner = item.querySelector(".product_item_inner");

        gsap.set(wrapper, { height: 0, overflow: "hidden" });
        gsap.set(paragraph, { opacity: 0 });

        const tl = gsap.timeline({ paused: true });

        tl.to(img, {
          maxWidth: "32rem",
          duration: 0.35,
          ease: "ease"
        }, 0);

        tl.to(wrapper, {
          height: "auto",
          duration: 0.25,
          ease: "ease"
        }, 0);

        tl.to(paragraph, {
          opacity: 1,
          duration: 0.25,
          ease: "ease"
        }, 0.05);

        item.addEventListener("mouseenter", () => tl.play());
        item.addEventListener("mouseleave", () => tl.reverse());
      });
    }

    if (mm.matches) init();

    mm.addEventListener("change", e => {
      if (e.matches) location.reload();
    });

  });

//Image slider automatic
window.Webflow = window.Webflow || [];
  window.Webflow.push(function () {
    gsap.registerPlugin(ScrollTrigger);

    const PX_PER_SEC = 40;

    function waitForImages(root) {
      const imgs = Array.from(root.querySelectorAll("img"));
      if (!imgs.length) return Promise.resolve();

      return Promise.all(
        imgs.map((img) => {
          if (img.complete && img.naturalWidth > 0) return Promise.resolve();
          return new Promise((res) => {
            img.addEventListener("load", res, { once: true });
            img.addEventListener("error", res, { once: true });
          });
        })
      );
    }

    gsap.utils.toArray(".who_gallery-breakout").forEach((viewport) => {
      const track = viewport.querySelector(".who_gallery-track");
      if (!track) return;

      let tween = null;

      const build = () => {
        if (tween) tween.kill();
        gsap.set(track, { x: 0 });

        track.querySelectorAll("[data-clone='true']").forEach((n) => n.remove());

        const originals = Array.from(track.children);
        const viewportW = viewport.clientWidth;

        const originalW = originals.reduce(
          (sum, el) => sum + el.getBoundingClientRect().width,
          0
        );

        if (!originalW) return;

        let currentW = originalW;
        while (currentW < viewportW * 2) {
          originals.forEach((el) => {
            const clone = el.cloneNode(true);
            clone.setAttribute("data-clone", "true");
            track.appendChild(clone);
          });
          currentW += originalW;
          if (track.children.length > 200) break;
        }

        const cycleW = originalW;

        tween = gsap.to(track, {
          x: -cycleW,
          duration: cycleW / PX_PER_SEC,
          ease: "none",
          repeat: -1,
          modifiers: {
            x: (x) => gsap.utils.wrap(-cycleW, 0, parseFloat(x)) + "px"
          }
        });

        ScrollTrigger.refresh();
      };

      const init = async () => {
        await waitForImages(track);
        build();
        setTimeout(build, 200);
        setTimeout(build, 800);
      };

      init();

      const onResize = () => {
        waitForImages(track).then(build);
      };

      window.addEventListener("resize", onResize);
      window.addEventListener("orientationchange", onResize);
    });
  });
